1299	// formatLoopResult returns a concise human-readable summary of a bead execution
1300	// result using merged/preserved/error terminology instead of raw status codes.
1301	func formatLoopResult(report ExecuteBeadReport) string {
1302		switch report.Status {
1303		case ExecuteBeadStatusSuccess:
1304			shortRev := report.ResultRev
1305			if len(shortRev) > 8 {
1306				shortRev = shortRev[:8]
1307			}
1308			if shortRev != "" {
1309				return fmt.Sprintf("merged (%s)", shortRev)
1310			}
1311			return "merged"
1312		case ExecuteBeadStatusAlreadySatisfied:
1313			return "already_satisfied"
1314		case ExecuteBeadStatusNoChanges:
1315			if report.NoChangesRationale != "" {
1316				return fmt.Sprintf("no_changes: %s", report.NoChangesRationale)
1317			}
1318			return "no_changes"
1319		default:
1320			detail := report.Detail
1321			if detail == "" {
1322				detail = report.Status
1323			}
1324			if report.PreserveRef != "" {
1325				return fmt.Sprintf("preserved: %s", detail)
1326			}
1327			return fmt.Sprintf("error: %s", detail)
1328		}
1329	}
