1331	// reCommitSHA matches a 7-to-40 character lowercase hex string that looks like a
1332	// git commit SHA. Used to detect whether a no_changes rationale cites a prior commit.
1333	var reCommitSHA = regexp.MustCompile(`\b[0-9a-f]{7,40}\b`)
1334	
1335	// reTestFuncName matches a Go test function name (TestXxx or BenchmarkXxx).
1336	var reTestFuncName = regexp.MustCompile(`\b(?:Test|Benchmark)[A-Z]\w*\b`)
1337	
1338	// rationaleIsSpecific returns true when the rationale string contains a reference
1339	// specific enough to treat a no_changes outcome as already_satisfied on the first
1340	// attempt. Currently this means: the rationale cites a commit SHA (7+ hex chars)
1341	// or a Go test function name. Vague rationales ("nothing to do") return false.
1342	func rationaleIsSpecific(rationale string) bool {
1343		if rationale == "" {
1344			return false
1345		}
1346		return reCommitSHA.MatchString(rationale) || reTestFuncName.MatchString(rationale)
1347	}
