1349	// adjudicateNoChangesContract is the NoChangesContract (TD-031 §8.1)
1350	// adjudication path. It returns whether the bead should be closed as
1351	// already_satisfied, the evidence string for the close, and the contract
1352	// event/label/body to record on the bead's event stream.
1353	//
1354	// Resolution order:
1355	//   - When SatisfactionChecker is configured it is consulted first and its
1356	//     result wins; ncEvent/ncLabel are empty (legacy escape valve, used by
1357	//     tests and integrations that pre-date the contract).
1358	//   - Otherwise the rationale is parsed for NoChangesContract markers:
1359	//   - verification_command: run it; exit 0 → already_satisfied with the
1360	//     no_changes_verified event recorded; non-zero → bead stays open with
1361	//     triage:no-changes-unverified label and no_changes_unverified event.
1362	//   - status: needs_investigation → bead stays open with
1363	//     triage:needs-investigation label and no_changes_needs_investigation
1364	//     event capturing the agent's reason.
1365	//   - neither marker present → bead stays open with
1366	//     triage:no-changes-unjustified label and no_changes_unjustified event.
1367	//
1368	// satisfied is the only signal the loop uses to decide close vs stay-open;
1369	// ncEvent/ncLabel/ncBody are recorded by the caller. Status is NEVER mutated
1370	// here to a non-canonical value (bd/br compatibility, ADR-004).
1371	func (w *ExecuteBeadWorker) adjudicateNoChangesContract(ctx context.Context, candidate bead.Bead, noChangesCount, maxNoChangesBeforeClose int, report ExecuteBeadReport, runtime ExecuteBeadLoopRuntime) (satisfied bool, evidence, ncEvent, ncLabel, ncBody string, err error) {
1372		if w.SatisfactionChecker != nil {
1373			s, ev, cerr := w.SatisfactionChecker.CheckSatisfied(ctx, candidate.ID, noChangesCount)
1374			return s, ev, "", "", "", cerr
1375		}
1376		parsed := ParseNoChangesRationale(report.NoChangesRationale)
1377		switch parsed.Kind {
1378		case NoChangesKindVerified:
1379			runner := w.VerificationRunner
1380			if runner == nil {
1381				runner = DefaultVerificationCommandRunner
1382			}
1383			exitCode, output, runErr := runner(ctx, runtime.ProjectRoot, parsed.VerificationCommand)
1384			body := fmt.Sprintf("verification_command=%s\nexit_code=%d", parsed.VerificationCommand, exitCode)
1385			if output != "" {
1386				body += "\noutput:\n" + output
1387			}
1388			if runErr != nil {
1389				body += "\nrun_error: " + runErr.Error()
1390			}
1391			if runErr == nil && exitCode == 0 {
1392				ev := fmt.Sprintf("verification_command passed: %s", parsed.VerificationCommand)
1393				return true, ev, NoChangesEventVerified, "", body, nil
1394			}
1395			return false, "", NoChangesEventUnverified, NoChangesLabelUnverified, body, nil
1396		case NoChangesKindNeedsInvestigation:
1397			body := parsed.NeedsInvestigationReason
1398			if body == "" {
1399				body = "(no reason provided)"
1400			}
1401			return false, "", NoChangesEventNeedsInvestigation, NoChangesLabelNeedsInvestigation, body, nil
1402		default: // NoChangesKindUnjustified
1403			body := strings.TrimSpace(report.NoChangesRationale)
1404			if body == "" {
1405				body = "(rationale absent)"
1406			}
1407			return false, "", NoChangesEventUnjustified, NoChangesLabelUnjustified, body, nil
1408		}
1409	}
