1427	// adjudicateNoChanges runs the no-change adjudication step for a bead.
1428	// It returns (satisfied, evidence, err). When satisfied is true the bead
1429	// should be closed as already_satisfied with the evidence string. When false
1430	// retry suppression (cooldown) should be applied and the bead left open.
1431	//
1432	// If a SatisfactionChecker is configured it is called first. Otherwise:
1433	//   - When the report carries a specific rationale (cites a commit SHA or test
1434	//     name), the bead is closed as already_satisfied on the first occurrence.
1435	//   - Otherwise the default count-based rule applies (close after maxNoChangesBeforeClose).
1436	func (w *ExecuteBeadWorker) adjudicateNoChanges(ctx context.Context, beadID string, noChangesCount, maxNoChangesBeforeClose int, rationale, acceptance, issueType, projectRoot string) (bool, string, error) {
1437		if w.SatisfactionChecker != nil {
1438			return w.SatisfactionChecker.CheckSatisfied(ctx, beadID, noChangesCount)
1439		}
1440		candidate := false
1441		evidence := ""
1442		switch {
1443		case rationaleIsSpecific(rationale):
1444			candidate = true
1445			evidence = rationale
1446		case noChangesCount >= maxNoChangesBeforeClose:
1447			candidate = true
1448			evidence = fmt.Sprintf("no_changes on %d consecutive attempt(s); bead treated as already satisfied", noChangesCount)
1449		}
1450		if !candidate {
1451			return false, "", nil
1452		}
1453		// Tighten the gate: when AC names structural properties (test functions,
1454		// deleted files, removed struct fields), refuse already_satisfied unless
1455		// each property holds in the worktree / rationale. Prevents false closes
1456		// where a regression suite passes but the AC's specific contract is unmet.
1457		//
1458		// operator-prompt beads carry an auto-generated AC stub (the prompt body
1459		// IS the contract); the structural verifier does not apply and is
1460		// skipped per Story 15 §Implementation #1.
1461		if issueType != bead.IssueTypeOperatorPrompt {
1462			if claims := ParseACClaims(acceptance); len(claims) > 0 {
1463				if ok, why := VerifyACClaims(claims, projectRoot, rationale); !ok {
1464					return false, why, nil
1465				}
1466			}
1467		}
1468		return true, evidence, nil
1469	}
