1478	// classifyReviewError maps a reviewer error and partial result into one of the
1479	// four FEAT-022 §12 taxonomy classes. Resolution order:
1480	//  1. reviewRes.Error if it's already one of the canonical class identifiers
1481	//     (the reviewer set it explicitly — preferred path).
1482	//  2. The error string text (for backwards-compatible reviewers that only
1483	//     embed the class in their message).
1484	//  3. ErrReviewVerdictUnparseable as a fallback when the strict-parse error
1485	//     leaks through a reviewer that did not set Error.
1486	//  4. Default to transport (network/provider-side failure) when nothing else
1487	//     matches.
1488	func classifyReviewError(reviewErr error, reviewRes *ReviewResult) string {
1489		if reviewRes != nil {
1490			switch reviewRes.Error {
1491			case evidence.OutcomeReviewContextOverflow,
1492				evidence.OutcomeReviewProviderEmpty,
1493				evidence.OutcomeReviewUnparseable,
1494				evidence.OutcomeReviewTransport:
1495				return reviewRes.Error
1496			}
1497		}
1498		msg := ""
1499		if reviewErr != nil {
1500			msg = reviewErr.Error()
1501		}
1502		switch {
1503		case strings.Contains(msg, evidence.OutcomeReviewContextOverflow):
1504			return evidence.OutcomeReviewContextOverflow
1505		case strings.Contains(msg, evidence.OutcomeReviewProviderEmpty):
1506			return evidence.OutcomeReviewProviderEmpty
1507		case strings.Contains(msg, evidence.OutcomeReviewUnparseable):
1508			return evidence.OutcomeReviewUnparseable
1509		case strings.Contains(msg, evidence.OutcomeReviewTransport):
1510			return evidence.OutcomeReviewTransport
1511		case reviewErr != nil && strings.Contains(msg, ErrReviewVerdictUnparseable.Error()):
1512			return evidence.OutcomeReviewUnparseable
1513		}
1514		return evidence.OutcomeReviewTransport
1515	}
1516	
1517	// reResultRevField extracts the result_rev value from a structured review-error
1518	// event body (one `result_rev=<sha>` line per event, written by
1519	// reviewErrorEventBody). The format is intentionally line-oriented so it
1520	// survives the AppendEvent body cap without losing the rev association.
1521	var reResultRevField = regexp.MustCompile(`(?m)^result_rev=([^\s]+)\s*$`)
1522	
1523	// countPriorReviewErrors returns the number of `review-error` events already
1524	// recorded against this bead whose body cites the given result_rev. This is
1525	// the FEAT-022 §14 retry counter — it is event-scoped (no separate counter
1526	// field on the bead) so a fresh result_rev naturally resets the count.
1527	func countPriorReviewErrors(store ExecuteBeadLoopStore, beadID, resultRev string) int {
1528		if resultRev == "" {
1529			return 0
1530		}
1531		events, err := store.Events(beadID)
1532		if err != nil {
1533			return 0
1534		}
1535		n := 0
1536		for _, ev := range events {
1537			if ev.Kind != "review-error" {
1538				continue
1539			}
1540			m := reResultRevField.FindStringSubmatch(ev.Body)
1541			if m == nil {
1542				continue
1543			}
1544			if m[1] == resultRev {
1545				n++
1546			}
1547		}
1548		return n
1549	}
1550	
1551	// reviewErrorEventBody is the canonical body shape for review-error and
1552	// review-manual-required events. It carries the failure class, attempt count,
1553	// and result_rev as discrete lines so operators can grep without parsing the
1554	// full reviewer error text. The trailing free-form message is the raw
1555	// reviewer-error string for forensics.
1556	func reviewErrorEventBody(class string, attemptCount int, resultRev, message string) string {
1557		var b strings.Builder
1558		fmt.Fprintf(&b, "failure_class=%s\n", class)
1559		fmt.Fprintf(&b, "attempt_count=%d\n", attemptCount)
1560		fmt.Fprintf(&b, "result_rev=%s\n", resultRev)
1561		if message != "" {
1562			b.WriteString("\n")
1563			b.WriteString(message)
1564		}
1565		return b.String()
1566	}
