1568	// shouldAttemptConflictRecovery returns true when the loop should try to reuse
1569	// a preserved iteration ref before discarding it. Requires a non-empty
1570	// ProjectRoot so recovery git commands have a working directory, and a
1571	// non-empty PreserveRef to actually have something to recover.
1572	func shouldAttemptConflictRecovery(report ExecuteBeadReport, runtime ExecuteBeadLoopRuntime) bool {
1573		if report.PreserveRef == "" || runtime.ProjectRoot == "" {
1574			return false
1575		}
1576		switch report.Status {
1577		case ExecuteBeadStatusLandConflict:
1578			return true
1579		case ExecuteBeadStatusExecutionFailed:
1580			// Attempt recovery when a commit was produced before the failure (e.g.
1581			// agent timed out mid-run). Both BaseRev and ResultRev must be set and
1582			// differ, because an empty BaseRev means we cannot confirm the agent
1583			// made any progress beyond the starting point.
1584			return report.BaseRev != "" && report.ResultRev != "" && report.ResultRev != report.BaseRev
1585		}
1586		return false
1587	}
