1589	// runConflictRecovery attempts to recover a preserved iteration before the loop
1590	// parks the bead as failed. Step 1: 3-way ort auto-merge (-X ours). Step 2 (if
1591	// step 1 fails and ConflictResolver is set): focused conflict-resolve agent.
1592	// Returns an updated ExecuteBeadReport whose Status is success when recovery
1593	// landed the commit, or land_conflict_unresolvable/land_conflict_needs_human
1594	// when all recovery paths failed.
1595	func (w *ExecuteBeadWorker) runConflictRecovery(
1596		ctx context.Context,
1597		b bead.Bead,
1598		report ExecuteBeadReport,
1599		runtime ExecuteBeadLoopRuntime,
1600		assignee string,
1601		now func() time.Time,
1602	) ExecuteBeadReport {
1603		var gitOps LandingGitOps = RealLandingGitOps{}
1604	
1605		autoFn := w.conflictAutoRecoverFn
1606		if autoFn == nil {
1607			autoFn = landConflictAutoRecover
1608		}
